import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"街头卖艺硬气功能力组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/防御类/街头卖艺硬气功能力组.md","filePath":"4.资源分区/6.技艺及称号/防御类/街头卖艺硬气功能力组.md"}'),p={name:"4.资源分区/6.技艺及称号/防御类/街头卖艺硬气功能力组.md"};function _(d,a,l,b,i,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"街头卖艺硬气功能力组",tabindex:"-1"},[s("街头卖艺硬气功能力组 "),e("a",{class:"header-anchor",href:"#街头卖艺硬气功能力组","aria-label":'Permalink to "街头卖艺硬气功能力组"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),o('<h1 id="街头卖艺硬气功能力组-1" tabindex="-1">街头卖艺硬气功能力组 <a class="header-anchor" href="#街头卖艺硬气功能力组-1" aria-label="Permalink to &quot;街头卖艺硬气功能力组&quot;">​</a></h1><p>街头卖艺硬气功能力组</p><p>此能力组总得来说都是一些类障眼法的能力，也不排除有真功夫，大部分都是表演性质，糊弄人可以，就是别把自己也骗了。每一项技艺一场景均只能使用一次，因为看过一遍就不新鲜了。只能在一次攻击中应用一项主动使用的街头卖艺硬气功能力。</p><p>胸口碎大石<br> 1000<br> 由于多年的摸爬滚打，即使现在被大石按在胸口也不会有什么事，有效的提升了人体防御力。<br> 以一个迅捷动作憋气，将一股气息憋在胸口处，在接下来的这一轮中，下一次受到攻击时，若攻击者没有选择攻击部位（即默认攻击躯干），则应对这次攻击额外获得2点临时生命和2点天生防御。</p><p>口吞宝剑<br> 1000<br> 口吞宝剑，即表演将剑从口中伸入腹中的技巧。<br> 当敌人使用剑、枪等笔直的武器攻击你时，你可以以一个反射动作立即张嘴去口吞宝剑，进行一次纯耐力属性检定，并抵消这次攻击中等同于耐力属性检定/3点那把武器的武器伤害。<br> 选开：若ST觉得口吞宝剑太过于老套无聊，且其同意开放此选开规则，则口吞宝剑改为肛门吞宝剑。</p><p>耐打王<br> 1000<br> 表演硬气功，最常见的形式就是助手拿棍棒，板砖一类的物品在表演者身上猛敲，并将表演用具震断。<br> 这是一项被动技艺，面对敌人疾风骤雨般的攻击，你始终要保持耐打王的尊严，你始终忽略3点多次攻击减值，并获得1点天生防御。</p><p>生吃热炭<br> 1000<br> 有一说一这东西已经算不上硬气功范畴了，更接近于江湖方士的装神弄鬼，总之就是你也不嫌烫。<br> 这是一项被动技艺，在伤害性质为火焰伤害的攻击结算步骤，生吃热炭将开始正常生效，你将立即陷入创伤来源的C级潮湿效果，这表现为你汗流浃背了，若免疫这个潮湿效果，则也无法正常令生吃热炭生效，仅应对这次攻击而言，获得3点火焰能量抗力。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",_]]);export{f as __pageData,m as default};
